/// <summary>
/// Extension of form datasource VendEditInvoice, VendInvoiceInfoLine
/// </summary>
[ExtensionOf(FormDataSourceStr(VendEditInvoice, VendInvoiceInfoLine))]
internal final class ETGVendEditInvoice_VendInvoiceInfoLine_Extension
{
    /// <summary>
    ///update design for custom fields
    /// </summary>
    /// <returns>int</returns>
    /// 
    private static RecId lastInvoiceRecId;
}

Method.Source:
public int active()
{
    int ret = next active();

    this.object(fieldNum(VendInvoiceInfoLine, ETGTermoValueUsageReal)).visible(VendParameters::find().ETGEnableTermoNumberFeature == NoYes::Yes);

    /// <summary>
    ///On submitting purchase invoice to wf, the invoice form should keep the same invoice number.
    /// </summary>

    if(ETGACFParameters::find().EnableUATSmallPoints == NoYes::Yes)
    {
        vendpackingsliptrans packingsliptrans;
        VendInvoiceInfoLine  vendInvoiceInfoLine = this.cursor();

        if (!vendInvoiceInfoLine.RecId && lastInvoiceRecId)
        {
            select firstOnly vendInvoiceInfoLine where vendInvoiceInfoLine.RecId == lastInvoiceRecId;
        }
        else
        {
            lastInvoiceRecId = vendInvoiceInfoLine.RecId;
        }
    }

    return ret;
}
